// Extract URL and check for #publish flag
const message = $input.first().json.message?.text || '';
const urlMatch = message.match(/https?:\/\/[^\s]+/);
const hasPublish = message.toLowerCase().includes('#publish');

if (!urlMatch) {
  throw new Error('Không tìm thấy URL trong tin nhắn!');
}

return [{
  json: {
    url: urlMatch[0],
    shouldPublish: hasPublish,
    chatId: $input.first().json.message?.chat?.id,
    originalMessage: message
  }
}];

// Parse Jina Reader Markdown output
const raw = $input.first().json.data || $input.first().json.body || '';
const prevData = $('Extract URL & Flags').first().json;

// Jina Reader returns: 'Title: ...\n\nURL Source: ...\n\nMarkdown Content:\n...'
// Extract title from 'Title:' line
const titleMatch = raw.match(/^Title:\s*(.+?)\n/m);
const pageTitle = titleMatch ? titleMatch[1].trim() : 'Untitled';

// Extract cover image from first ![Image](...) in markdown
const imgMatch = raw.match(/!\[.*?\]\((https?:\/\/[^)]+)\)/);
const coverImage = imgMatch ? imgMatch[1] : '';

// Extract ALL image URLs from markdown BEFORE any trimming
const allImageMatches = [...raw.matchAll(/!\[([^\]]*)\]\((https?:\/\/[^)]+)\)/g)];
const imageUrls = allImageMatches
  .map(m => ({ alt: m[1] || '', url: m[2] }))
  .filter(img => !img.url.includes('banner') && !img.url.includes('affiliate') && !img.url.includes('contact-sales'));

// Get main content (everything after 'Markdown Content:' or after the metadata)
let content = raw;
const mdContentIdx = raw.indexOf('Markdown Content:');
if (mdContentIdx !== -1) {
  content = raw.substring(mdContentIdx + 17);
} else {
  // Fallback: skip Title/URL/Published metadata lines
  const lines = raw.split('\n');
  const startIdx = lines.findIndex((l, i) => i > 2 && !l.startsWith('Title:') && !l.startsWith('URL Source:') && !l.startsWith('Published') && !l.startsWith('Warning:') && l.trim().length > 0);
  if (startIdx > 0) content = lines.slice(startIdx).join('\n');
}

// Remove regular links but keep text (preserve image markdown)
content = content.replace(/(?<!!)\[([^\]]+)\]\(.*?\)/g, '$1');
// Clean excessive whitespace
content = content.replace(/\n{3,}/g, '\n\n').trim();

// Limit content to avoid AI timeout
if (content.length > 8000) {
  content = content.substring(0, 8000) + '\n\n[... nội dung đã được cắt bớt]';
}

// Append image list so AI always has all image URLs even if content was truncated
if (imageUrls.length > 0) {
  content += '\n\n--- DANH SÁCH ẢNH GỐC (PHẢI chèn tất cả vào bài viết) ---\n';
  imageUrls.forEach((img, i) => {
    content += `Ảnh ${i + 1}: ${img.url}\n`;
  });
}

return [{
  json: {
    pageTitle,
    coverImage,
    rawContent: content,
    url: prevData.url,
    shouldPublish: prevData.shouldPublish,
    chatId: prevData.chatId
  }
}];

// Parse AI Agent response and prepare blog post data
const aiResponse = $input.first().json;
const prevData = $('Clean HTML').first().json;

// AI Agent trả output ở field 'output' hoặc 'text'
const rawOutput = aiResponse.output || aiResponse.text || JSON.stringify(aiResponse);

let aiContent;
try {
  // Remove markdown code blocks if present
  const cleaned = rawOutput.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  aiContent = JSON.parse(cleaned);
} catch (e) {
  throw new Error('AI trả về không đúng format JSON: ' + e.message + '\nRaw output: ' + rawOutput.substring(0, 500));
}

const status = prevData.shouldPublish ? 'published' : 'draft';

return [{
  json: {
    title: aiContent.title || prevData.pageTitle,
    slug: aiContent.slug || prevData.pageTitle.toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-'),
    excerpt: aiContent.excerpt || '',
    content: aiContent.content || '',
    cover_image: prevData.coverImage || '',
    category_slug: aiContent.category_slug || 'meo-mua-sam',
    category_name: aiContent.category_name || 'Mẹo mua sắm',
    tags: aiContent.tags || [],
    status: status,
    chatId: prevData.chatId,
    sourceUrl: prevData.url
  }
}];

